# Category: oauth_security

import os
from flask import Flask, redirect, url_for, session, request, jsonify
from authlib.integrations.flask_client import OAuth

app = Flask(__name__)
app.secret_key = os.urandom(24)

# Load configuration from environment variables or a config file
# For simplicity, using os.environ here. In production, consider Flask config or a dedicated config manager.
app.config['OAUTH_CLIENT_ID'] = os.environ.get('OAUTH_CLIENT_ID', 'your_client_id')
app.config['OAUTH_CLIENT_SECRET'] = os.environ.get('OAUTH_CLIENT_SECRET', 'your_client_secret')
app.config['OAUTH_AUTHORIZE_URL'] = os.environ.get('OAUTH_AUTHORIZE_URL', 'https://example.com/oauth/authorize')
app.config['OAUTH_TOKEN_URL'] = os.environ.get('OAUTH_TOKEN_URL', 'https://example.com/oauth/token')
app.config['OAUTH_API_BASE_URL'] = os.environ.get('OAUTH_API_BASE_URL', 'https://example.com/api/')

# Multi-tenant configuration: Each tenant can have a different redirect_uri configured.
# This would typically come from a database based on a tenant_id or client_id.
# For this example, we'll simulate a configurable redirect_uri and a domain check.
TENANT_CONFIG = {
    'tenant1': {
        'redirect_uri': 'http://localhost:5000/auth/callback/tenant1',
        'domain': 'localhost:5000' # The expected domain for this tenant's redirect URIs
    },
    'tenant2': {
        'redirect_uri': 'http://sub.example.com/auth/callback/tenant2',
        'domain': 'example.com' # The expected domain for this tenant, covering subdomains
    }
}

oauth = OAuth(app)

# Register the OAuth provider dynamically
# In a real multi-tenant scenario, you might have multiple providers or register them based on tenant.
# For simplicity, we register a single 'my_provider' and dynamically adjust its redirect_uri per request.
oauth.register(
    name='my_provider',
    client_id=app.config['OAUTH_CLIENT_ID'],
    client_secret=app.config['OAUTH_CLIENT_SECRET'],
    authorize_url=app.config['OAUTH_AUTHORIZE_URL'],
    token_url=app.config['OAUTH_TOKEN_URL'],
    api_base_url=app.config['OAUTH_API_BASE_URL'],
    client_kwargs={'scope': 'profile email'},
)

@app.route('/')
def index():
    return '''
        <h1>OAuth 2.0 Client (Multi-Tenant Simulation)</h1>
        <p>Choose a tenant to initiate OAuth flow:</p>
        <ul>
            <li><a href="/login/tenant1">Login with Tenant 1 (localhost:5000)</a></li>
            <li><a href="/login/tenant2">Login with Tenant 2 (sub.example.com)</a></li>
        </ul>
        <p><a href="/logout">Logout</a></p>
        <p>Session data: {}</p>
    '''.format(session.get('user', 'Not logged in'))

@app.route('/login/<tenant_id>')
def login(tenant_id):
    if tenant_id not in TENANT_CONFIG:
        return jsonify(error="Tenant not found"), 404

    tenant_config = TENANT_CONFIG[tenant_id]
    configured_redirect_uri = tenant_config['redirect_uri']
    expected_domain = tenant_config['domain']

    # --- Redirect URI Validation ---
    # In a real scenario, the incoming `redirect_uri` might come from a query parameter
    # if the client allows dynamic redirect_uri per request, or from a pre-configured database.
    # Here, we're using the pre-configured one, but validating it against the tenant's domain.
    # This check ensures that even if a misconfigured redirect_uri exists, it belongs to the right domain.
    if expected_domain not in configured_redirect_uri:
        return jsonify(error=f"Misconfiguration: Redirect URI '{configured_redirect_uri}' does not match expected domain '{expected_domain}' for tenant '{tenant_id}'."), 500

    session['tenant_id'] = tenant_id # Store tenant_id in session for callback

    # Initiate authorization flow with the tenant-specific redirect_uri
    return oauth.my_provider.authorize_redirect(redirect_uri=configured_redirect_uri)

@app.route('/auth/callback/<tenant_id>')
def auth_callback(tenant_id):
    if 'tenant_id' not in session or session['tenant_id'] != tenant_id:
        return jsonify(error="Invalid tenant context or session mismatch"), 400

    if tenant_id not in TENANT_CONFIG:
        return jsonify(error="Tenant not found"), 404

    tenant_config = TENANT_CONFIG[tenant_id]
    configured_redirect_uri = tenant_config['redirect_uri']
    expected_domain = tenant_config['domain']

    # Ensure the redirect_uri used for the callback matches the one configured and used for authorization.
    # And re-validate against the domain for an extra layer of security.
    if expected_domain not in configured_redirect_uri:
        return jsonify(error=f"Security alert: Callback redirect URI '{configured_redirect_uri}' does not match expected domain '{expected_domain}' for tenant '{tenant_id}'."), 500

    # The token method automatically handles exchanging the authorization code for an access token
    # It also validates the state parameter to prevent CSRF.
    try:
        token = oauth.my_provider.authorize_access_token()
        session['user'] = token # Store token or user info in session
        return redirect(url_for('index'))
    except Exception as e:
        app.logger.error(f"OAuth callback error: {e}")
        return jsonify(error=f"OAuth callback failed: {e}"), 400

@app.route('/logout')
def logout():
    session.pop('user', None)
    session.pop('tenant_id', None)
    return redirect(url_for('index'))

